import React, {  useNavigate, useEffect, useState } from "react";
import {useLocation} from "react-router-dom";
import './Logout.css';
import './Welcome';
import axios from "axios";
function Logout () {
    const [responses, setResponse] = useState([]); 
    useEffect((userName) => {
        axios.get(`http://localhost:8080/user/${userName}/items`).then(response => setResponse(response.data))
        .catch(error => {console.log("An error happened:" + error)})
    }, []);
    const navigate = () => {
         useNavigate();
    }
    const location = useLocation();
    console.log(location)
    return (
        <div className="list-of-itmes">
         <div className="nav-bar">
        <div className="header">
        <a href="#default" className="logo">Productiv</a>
        <div className="header-right">
       {/* Create loader! */}
        <a href="#home">My Account</a>
        <a href="/" onClick={() => navigate('/')} >Logout</a>
        </div>
        </div>
            <h1>Welcome {location.state.userName}!</h1>
        </div>
            <ul>
                {
                    responses.map(response => (<li>{response.id} - {response.userName} - {response.targetDate} - {response.done}</li>))
                }
            </ul>
        </div>
    )
}

export default Logout;
